var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"와아…… 밖에서 봤을 때는 허름했는데 안은 무척 아름다워요.","JPN":"わあ……外から見た時は古びて見えましたけど、中はとても美しいですね。","ENG":"Wow... It looked so run-down on the outside, but the inside is beautiful.","TWN":"哇啊……從外面看破破爛爛的，裡面卻好漂亮啊。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"여기가 발렌티누스 수도원인가? 음침하게 사는 줄 알았더니 영 딴판이네.","JPN":"ここがバレンチヌス修道院？　薄暗い感じで生活してるのかと思ったら全然違うんだね。","ENG":"Is this the Valentinus Monastery? I imagined it would be creepier than this.","TWN":"這裡就是聖華倫修道院嗎？我還以為會很陰森，結果正好相反呢。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어차피 겉만 그럴싸할 뿐이겠죠. 뒤에서는 무슨 음험한 짓을 저지르고 있을지 모릅니다.","JPN":"どうせ外見がそれらしいだけでしょう。裏ではどんな陰険なことをしているかわかりませんわ。","ENG":"Do not be fooled by its exterior. We do not know what insidious activities are happening behind those walls.","TWN":"反正只是外表看起來還不錯而已吧。不知道在背後搞什麼鬼。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Kgh...","TWN":"呃……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"힘들어 보이는군. 실키 양 때문에 부상을 숨기려는 건가?","JPN":"辛そうだな。シルキー君のために怪我を隠しているのかね？","ENG":"You don't look so good. Were you hiding your pain because of Sylkie?","TWN":"你看起來很難受。是因為思琪，才故意隱瞞傷勢嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잠시라도 괜찮으니, 쉬는 편이 좋겠네만.","JPN":"少しの間だけでも、休んだ方がよさそうだが。","ENG":"I think you should rest, even for a little while.","TWN":"哪怕是一下也好，你還是休息一下比較好。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……걱정해 주셔서 고맙지만, 아직 버틸 수 있어요.","JPN":"……ご心配してくださるのは感謝しますが、まだ耐えられますわ。","ENG":"...Thank you for your consideration, but I can handle myself.","TWN":"……謝謝你擔心我，不過我還能撐住。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 약한 모습을 보이면 그 음험한 작자들이 무슨 짓을 할지 모르니까요.","JPN":"私が弱い姿を見せれば、あの陰険な者たちが何をしてくるかわかりませんから。","ENG":"If I show any signs of weakness to them, those insidious ones might jump at the opportunity.","TWN":"如果我露出軟弱的一面，不知道那些陰險的傢伙，又會做出什麼事來。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NUN_NPC_ESPR2_NULL","text":{"KOREA":"후훗, 말씀이 심하시네. 음험하기로는 맥크레디 가문에 견줄 곳이 없을 텐데.","JPN":"ふふっ、酷いわね。陰険さでいったらマクレディー家に敵うところはないないはずだけど。","ENG":"Ha ha. That's a little harsh. If you're talking insidious, then the MacCready family is none to compare.","TWN":"呵呵，這話說得太過分了。要說陰險，誰也比不上麥克蕾蒂家族。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"NUN_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나, 혹시 수도원에서 왔다던 사람이 저 분인가요?","JPN":"ルナさん、修道院から来たという人はあの方ですか？","ENG":"Luna, is this the person who came from the monastery?","TWN":"露娜，你說的從修道院來的人是她嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"응. 아그네스 아비게일. 분명 자기가 종교학부장이라고 했어.","JPN":"うん。アグネス・アビゲイル。確か宗教学部長だって言ってた。","ENG":"Uh-huh. Agnes Abigail. She said that she was the Dean of Religion.","TWN":"嗯，艾格妮絲·亞比該，她說自己是宗教學院院長。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"오랜만이야, 부학회장님. 숲에 풀어 둔 파수견들 때문에 많이 놀랐지?","JPN":"久しぶりね、副学会長。森に放っておいた番犬のせいでずいぶんと驚いたでしょう？","ENG":"Long time no see, Ms. Vice President. Were you startled by the guard dogs in the forest?","TWN":"好久不見，副學會長。森林裡的守衛犬嚇到你了吧？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"종을 더 일찍 울렸어야 했는데 미안해. 고해소를 정리하느라 확인이 늦었거든.","JPN":"もっと早くに鐘を鳴らすべきだったのに、ごめんなさいね。告解部屋を片付けていたら確認が遅れてしまって。","ENG":"My apologies. I should've rung the bell sooner, but I was preoccupied with organizing the confessions.","TWN":"我應該早點敲鐘的，對不起。我忙著收拾告解室，所以這麼晚才發現。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"따라와. 부상을 치료해 줄게.","JPN":"ついてきて。怪我を治療してあげる。","ENG":"Come with me. I will treat your wounds.","TWN":"跟我來，我會為你治療。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 저 분이랑 아는 사이셨어요?","JPN":"副学会長様、あの方とお知り合いだったんですか？","ENG":"Vice President, do you know this person?","TWN":"副學會長，你認識那個人嗎？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨…. 아무리 기억을 되짚어 봐도 처음 뵙는 분이에요.","JPN":"いいえ……どう考えても初めて会う方ですわ。","ENG":"No... I have no recollection of her in my memories.","TWN":"不認識……不管我怎麼回想，我跟她應該是第一次見面。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 지금은 저 사람 말을 따르는 편이 좋겠군.","JPN":"だが、今はあの人の言葉に従った方がよさそうだ。","ENG":"Nevertheless, I believe listening to her is best here.","TWN":"不過現在還是照著那個人說的去做比較好。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};